export type ParsedMigrateMarketPositionInstruction<
  TProgram extends string = typeof PERPETUALS_PROGRAM_ADDRESS,
  TAccountMetas extends readonly AccountMeta[] = readonly AccountMeta[],
> = {
  programAddress: Address<TProgram>;
  accounts: {
    admin: TAccountMetas[0];
    multisig: TAccountMetas[1];
    perpetuals: TAccountMetas[2];
    pool: TAccountMetas[3];
    oldPosition: TAccountMetas[4];
    oldMarket: TAccountMetas[5];
    oldCollateralCustody: TAccountMetas[6];
    oldCollateralOracleAccount: TAccountMetas[7];
    newPosition: TAccountMetas[8];
    newMarket: TAccountMetas[9];
    newCollateralCustody: TAccountMetas[10];
    newCollateralOracleAccount: TAccountMetas[11];
    eventAuthority: TAccountMetas[12];
    program: TAccountMetas[13];
    ixSysvar: TAccountMetas[14];
    systemProgram: TAccountMetas[15];
  };
  data: MigrateMarketPositionInstructionData;
};

export function parseMigrateMarketPositionInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedMigrateMarketPositionInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 16) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 16,
      },
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      admin: getNextAccount(),
      multisig: getNextAccount(),
      perpetuals: getNextAccount(),
      pool: getNextAccount(),
      oldPosition: getNextAccount(),
      oldMarket: getNextAccount(),
      oldCollateralCustody: getNextAccount(),
      oldCollateralOracleAccount: getNextAccount(),
      newPosition: getNextAccount(),
      newMarket: getNextAccount(),
      newCollateralCustody: getNextAccount(),
      newCollateralOracleAccount: getNextAccount(),
      eventAuthority: getNextAccount(),
      program: getNextAccount(),
      ixSysvar: getNextAccount(),
      systemProgram: getNextAccount(),
    },
    data: getMigrateMarketPositionInstructionDataDecoder().decode(
      instruction.data,
    ),
  };
}
